"""Fixed-s2 cross-N Bayes factor: is the extra component real?

Profiled-s2 lnZ is an empirical-Bayes (profile) Z and is NOT comparable across
component count N. Only the fixed-s2 ladder gives a clean cross-N Bayes factor.
A component is statistically real only if ΔlnZ(N+1 vs N) is consistently
positive (>~5) across ALL s2 values; a sign flip with the prior scale means the
extra component is prior-driven, not data-driven.
"""

import glob
import json
import os
import re
from collections import defaultdict

D = os.path.dirname(__file__)
recs = {}
for f in glob.glob(os.path.join(D, "*_joint_fit*.json")):
    d = json.load(open(f))
    m = re.match(r"(.+?)_joint_fit_(.*)\.json", os.path.basename(f))
    if not m:
        continue
    burst, tag = m.group(1), m.group(2)
    recs[(burst, tag)] = (d.get("log_evidence"), (d.get("alpha") or {}).get("median"))

# group by burst, find s2 grids and the C/D pairs that differ by one component
s2vals = [1, 10, 100]
bursts = sorted({b for (b, _) in recs})
for b in bursts:
    tags = [t for (bb, t) in recs if bb == b]
    s2tags = [t for t in tags if "_s2-" in t]
    if not s2tags:
        continue
    # base config (CxDy) -> dict of s2 -> lnZ
    grids = defaultdict(dict)
    for t in s2tags:
        base, s2 = t.split("_s2-")
        grids[base][int(s2)] = recs[(b, t)]
    bases = sorted(grids)
    print(f"\n===== {b} : fixed-s2 cross-N test =====")
    for base in bases:
        line = f"  {base:6}"
        for s in s2vals:
            v = grids[base].get(s)
            line += f"  s2={s:<3} lnZ={v[0]:.1f}" if v else f"  s2={s:<3} --      "
        print(line)

    # pairwise: for configs differing by exactly one component (C+1 or D+1)
    def cd(base):
        mm = re.match(r"C(\d+)D(\d+)", base)
        return (int(mm.group(1)), int(mm.group(2)))

    for i, a in enumerate(bases):
        for bb in bases:
            ca, da = cd(a)
            cb, db = cd(bb)
            if (cb == ca + 1 and db == da) or (db == da + 1 and cb == ca):
                deltas = []
                for s in s2vals:
                    va, vb = grids[a].get(s), grids[bb].get(s)
                    if va and vb:
                        deltas.append(vb[0] - va[0])
                if deltas:
                    signs = {("+" if x > 0 else "-") for x in deltas}
                    verdict = (
                        "REAL (consistent +)"
                        if all(x > 5 for x in deltas)
                        else (
                            "NOT robust (sign flips)" if len(signs) > 1 else "weak/consistent-neg"
                        )
                    )
                    ds = " / ".join(f"{x:+.1f}" for x in deltas)
                    print(f"    Δ({bb} vs {a}) across s2: {ds}   -> {verdict}")
